import (
	context "context"
	fern "github.com/no-content-response/fern"
	fernclient "github.com/no-content-response/fern/client"
)

client := fernclient.NewClient()
response, err := client.Contacts.Create(
	context.TODO(),
	&fern.CreateContactRequest{
		Name: "name",
	},
)

